/**
 * Unit Tests: S3StorageService
 * Testa o módulo de storage multi-provider (local, supabase, s3)
 * @see src/lib/s3-storage.ts
 */

import { S3StorageService } from '@/lib/s3-storage';
import { promises as fs } from 'fs';
import path from 'path';

// Mock external dependencies
jest.mock('@aws-sdk/client-s3', () => ({
  S3Client: jest.fn().mockImplementation(() => ({
    send: jest.fn(),
  })),
  GetObjectCommand: jest.fn(),
  PutObjectCommand: jest.fn(),
  DeleteObjectCommand: jest.fn(),
  HeadObjectCommand: jest.fn(),
}));

jest.mock('@supabase/supabase-js', () => ({
  createClient: jest.fn().mockReturnValue({
    storage: {
      from: jest.fn().mockReturnValue({
        upload: jest.fn().mockResolvedValue({ error: null }),
        download: jest.fn().mockResolvedValue({ data: new Blob(['test']), error: null }),
        remove: jest.fn().mockResolvedValue({ error: null }),
        list: jest.fn().mockResolvedValue({ data: [{ name: 'test.mp4' }], error: null }),
        getPublicUrl: jest.fn().mockReturnValue({ data: { publicUrl: 'https://example.com/test.mp4' } }),
        createSignedUrl: jest.fn().mockResolvedValue({ data: { signedUrl: 'https://example.com/signed' }, error: null }),
      }),
    },
  }),
}));

// Helper to set storage provider
function setProvider(provider: string) {
  process.env.STORAGE_PROVIDER = provider;
}

describe('S3StorageService', () => {
  const originalEnv = { ...process.env };

  beforeEach(() => {
    jest.clearAllMocks();
    // Default to local storage for tests
    process.env.STORAGE_PROVIDER = 'local';
  });

  afterEach(() => {
    process.env = { ...originalEnv };
  });

  describe('getProvider resolution', () => {
    it('should default to local when STORAGE_PROVIDER is not set', () => {
      delete process.env.STORAGE_PROVIDER;
      // The provider is resolved internally; we test via behavior
      // Local provider uses fs operations
      expect(S3StorageService).toBeDefined();
    });

    it('should accept supabase provider', () => {
      setProvider('supabase');
      expect(S3StorageService).toBeDefined();
    });

    it('should accept s3 provider', () => {
      setProvider('s3');
      expect(S3StorageService).toBeDefined();
    });
  });

  describe('uploadFile', () => {
    it('should upload file with local provider and return path', async () => {
      setProvider('local');
      const mockBuffer = Buffer.from('test content');
      const mockMkdir = jest.spyOn(fs, 'mkdir').mockResolvedValue(undefined);
      const mockWriteFile = jest.spyOn(fs, 'writeFile').mockResolvedValue();

      const url = await S3StorageService.uploadFile('test/file.mp4', mockBuffer, 'video/mp4');

      expect(url).toBe('/uploads/test/file.mp4');
      expect(mockMkdir).toHaveBeenCalledWith(
        expect.stringContaining('test'),
        { recursive: true }
      );
      expect(mockWriteFile).toHaveBeenCalledWith(
        expect.stringContaining('file.mp4'),
        mockBuffer
      );

      mockMkdir.mockRestore();
      mockWriteFile.mockRestore();
    });

    it('should upload to supabase and return public URL', async () => {
      setProvider('supabase');
      process.env.SUPABASE_URL = 'https://test.supabase.co';
      process.env.SUPABASE_SERVICE_ROLE_KEY = 'test-service-key';
      process.env.SUPABASE_STORAGE_BUCKET = 'assets';

      const mockBuffer = Buffer.from('test content');
      const url = await S3StorageService.uploadFile('test/file.mp4', mockBuffer, 'video/mp4');

      expect(url).toBe('https://example.com/test.mp4');
    });

    it('should upload to S3 and return URL', async () => {
      setProvider('s3');
      process.env.AWS_REGION = 'us-east-1';
      process.env.AWS_S3_BUCKET = 'my-bucket';

      const { S3Client } = require('@aws-sdk/client-s3');
      S3Client.mockImplementation(() => ({
        send: jest.fn().mockResolvedValue({}),
      }));

      const mockBuffer = Buffer.from('test content');
      const url = await S3StorageService.uploadFile('test/file.mp4', mockBuffer, 'video/mp4');

      expect(url).toBe('https://my-bucket.s3.us-east-1.amazonaws.com/test/file.mp4');
    });
  });

  describe('downloadFile', () => {
    it('should download file from local storage', async () => {
      setProvider('local');
      const mockBuffer = Buffer.from('file content');
      const mockReadFile = jest.spyOn(fs, 'readFile').mockResolvedValue(mockBuffer);

      const result = await S3StorageService.downloadFile('test/file.mp4');

      expect(result.success).toBe(true);
      expect(result.buffer).toEqual(mockBuffer);

      mockReadFile.mockRestore();
    });

    it('should return error on local file not found', async () => {
      setProvider('local');
      jest.spyOn(fs, 'readFile').mockRejectedValue(new Error('ENOENT'));

      const result = await S3StorageService.downloadFile('nonexistent.mp4');

      expect(result.success).toBe(false);
      expect(result.error).toContain('ENOENT');

      jest.restoreAllMocks();
    });

    it('should download from supabase', async () => {
      setProvider('supabase');
      process.env.SUPABASE_URL = 'https://test.supabase.co';
      process.env.SUPABASE_SERVICE_ROLE_KEY = 'test-service-key';

      const result = await S3StorageService.downloadFile('test/file.mp4');

      expect(result.success).toBe(true);
      expect(result.buffer).toBeDefined();
    });
  });

  describe('fileExists', () => {
    it('should check local file existence - exists', async () => {
      setProvider('local');
      jest.spyOn(fs, 'access').mockResolvedValue();

      const exists = await S3StorageService.fileExists('test/file.mp4');
      expect(exists).toBe(true);

      jest.restoreAllMocks();
    });

    it('should check local file existence - not exists', async () => {
      setProvider('local');
      jest.spyOn(fs, 'access').mockRejectedValue(new Error('ENOENT'));

      const exists = await S3StorageService.fileExists('test/file.mp4');
      expect(exists).toBe(false);

      jest.restoreAllMocks();
    });

    it('should check supabase file existence', async () => {
      setProvider('supabase');
      process.env.SUPABASE_URL = 'https://test.supabase.co';
      process.env.SUPABASE_SERVICE_ROLE_KEY = 'test-service-key';

      const exists = await S3StorageService.fileExists('test/test.mp4');
      // Mock returns [{ name: 'test.mp4' }] so should find file
      expect(exists).toBe(true);
    });

    it('should return false when S3 bucket not configured', async () => {
      setProvider('s3');
      delete process.env.AWS_S3_BUCKET;

      const exists = await S3StorageService.fileExists('test/file.mp4');
      expect(exists).toBe(false);
    });
  });

  describe('deleteFile', () => {
    it('should delete local file', async () => {
      setProvider('local');
      const mockRm = jest.spyOn(fs, 'rm').mockResolvedValue();

      await S3StorageService.deleteFile('test/file.mp4');

      expect(mockRm).toHaveBeenCalledWith(
        expect.stringContaining('file.mp4'),
        { force: true }
      );

      mockRm.mockRestore();
    });

    it('should delete supabase file', async () => {
      setProvider('supabase');
      process.env.SUPABASE_URL = 'https://test.supabase.co';
      process.env.SUPABASE_SERVICE_ROLE_KEY = 'test-service-key';

      await expect(S3StorageService.deleteFile('test/file.mp4')).resolves.not.toThrow();
    });

    it('should throw when deleting S3 file without bucket', async () => {
      setProvider('s3');
      delete process.env.AWS_S3_BUCKET;

      await expect(S3StorageService.deleteFile('test/file.mp4'))
        .rejects.toThrow('AWS_S3_BUCKET not configured');
    });
  });

  describe('getSignedUrl', () => {
    it('should return local path for local provider', async () => {
      setProvider('local');

      const url = await S3StorageService.getSignedUrl('test/file.mp4');

      expect(url).toBe('/uploads/test/file.mp4');
    });

    it('should return signed URL for supabase', async () => {
      setProvider('supabase');
      process.env.SUPABASE_URL = 'https://test.supabase.co';
      process.env.SUPABASE_SERVICE_ROLE_KEY = 'test-service-key';

      const url = await S3StorageService.getSignedUrl('test/file.mp4', 7200);

      expect(url).toBe('https://example.com/signed');
    });

    it('should return public S3 URL for s3 provider', async () => {
      setProvider('s3');
      process.env.AWS_REGION = 'eu-west-1';
      process.env.AWS_S3_BUCKET = 'my-bucket';

      const url = await S3StorageService.getSignedUrl('test/file.mp4');

      expect(url).toBe('https://my-bucket.s3.eu-west-1.amazonaws.com/test/file.mp4');
    });
  });
});
